sql:
SELECT status_name 
FROM admission_statuses 
WHERE status_id = 1;

SELECT IFNULL(category_id, -1) AS identifier FROM categories
UNION
SELECT IFNULL(seat_type_id, -1) AS identifier FROM seat_types;

SELECT seat_type_name
FROM seat_types
WHERE seat_type_id = 1;

SELECT d.document_id, c.category_name
FROM documents d
JOIN categories c ON d.document_type = c.category_name;

external_knowledge:
- "gates that have opened their doors to the chosen few" refers to the rounds of admission after the first one; 
- "banners and mottos" are metaphorical expressions for `round_name` and `description`;
- "initial welcome" represents the first round of admission with `admission_round_id` 1.

sql:
SELECT round_name, description
FROM admission_rounds
WHERE admission_round_id > 1;

SELECT status_id, status_name, description
FROM admission_statuses
WHERE status_id > 5;

SELECT candidate_id
FROM documents
WHERE document_type = 'Certificate' AND verification_status = 'pending';

SELECT document_type, document_url, verification_status
FROM documents
ORDER BY verification_status;

SELECT COUNT(*) 
FROM categories 
WHERE category_id = 1;

SELECT COUNT(*) 
FROM admission_rounds 
WHERE start_date >= '2023-02-01' AND end_date <= '2023-02-28';

SELECT document_type, document_url, verification_status 
FROM documents 
WHERE document_id = 1;
